SELECT studio_test_name, description
FROM studio_tests
WHERE studio_test_id = 0;

SELECT COUNT(*)
FROM studio_tests
WHERE test_type = 'Assessment' AND expected_duration > 45;

SELECT AVG(pm.metric_value) AS average_metric_value
FROM performance_metrics pm
WHERE pm.participant_id = 0 AND pm.metric_name = 'Music_score_reading_completeness';
